const express = require('express');
const jwt = require('jsonwebtoken');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

mongoose.connect('mongodb://localhost/auth', { useNewUrlParser: true, useUnifiedTopology: true });

const User = mongoose.model('User', {
  username: String,
  password: String
});

const secretKey = 'your-secret-key';

app.post('/api/login', async (req, res) => {
  try {
    const user = await User.findOne({ username: req.body.username });
    if (!user || user.password !== req.body.password) {
      return res.status(401).json({ message: 'Invalid credentials' });
    }
    const token = jwt.sign({ userId: user._id }, secretKey, { expiresIn: '1h' });
    res.json({ token });
  } catch (err) {
    console.error(err);
    res.status(500).json({ message: 'Internal Server Error' });
  }
});

const rateLimit = require('express-rate-limit');
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 50 // limit each IP to 50 requests per `window` (here, 15 minutes)
});
app.use(limiter);

const helmet = require('helmet');
app.use(helmet());

const mongoSanitize = require('mongo-sanitize');
app.use(mongoSanitize());

const csurf = require('csurf');
const csrfProtection = csurf();
app.use(csrfProtection);
app.use((req, res, next) => {
  res.locals.csrfToken = req.csrfToken();
  next();
});

const abuseTracker = {};
app.post('/api/login', (req, res) => {
  const ip = req.ip;
  if (!abuseTracker[ip]) {
    abuseTracker[ip] = { count: 0, lastAttempt: null };
  }
  const now = Date.now();
  if (now - abuseTracker[ip].lastAttempt < 15 * 60 * 1000) {
    return res.status(429).json({ message: 'Too many attempts' });
  }
  abuseTracker[ip].count++;
  abuseTracker[ip].lastAttempt = now;
});

const port = 3000;
app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});